import jwt
from datetime import datetime
import json

def decode_and_verify_jwt(token, secret, algorithms=None, required_claims=None):
    """
    Decode and verify JWT token for debugging purposes
    
    Args:
        token (str): JWT token to decode
        secret (str): Secret key for signature verification
        algorithms (list): List of allowed algorithms (e.g., ['HS256'])
        required_claims (list): List of required claims (e.g., ['exp', 'iat'])
    
    Returns:
        dict: Decoded token payload if valid, None if invalid
    """
    if algorithms is None:
        algorithms = ['HS256']
    
    if required_claims is None:
        required_claims = ['exp']
    
    try:
        # Decode and verify the token
        payload = jwt.decode(
            token,
            secret,
            algorithms=algorithms,
            options={
                'verify_signature': True,
                'verify_exp': True,
                'verify_iat': True,
                'verify_nbf': True
            }
        )
        
        # Check for required claims
        for claim in required_claims:
            if claim not in payload:
                print(f"Missing required claim: {claim}")
                return None
        
        # Verify expiration if present
        if 'exp' in payload:
            exp_timestamp = payload['exp']
            if isinstance(exp_timestamp, str):
                exp_timestamp = int(exp_timestamp)
            if exp_timestamp < datetime.utcnow().timestamp():
                print("Token has expired")
                return None
        
        return payload
        
    except jwt.ExpiredSignatureError:
        print("Token has expired")
        return None
    except jwt.InvalidTokenError as e:
        print(f"Invalid token: {str(e)}")
        return None
    except Exception as e:
        print(f"Error decoding token: {str(e)}")
        return None

def debug_jwt_token(token, secret, algorithms=None):
    """
    Debug utility to print detailed information about a JWT token
    
    Args:
        token (str): JWT token to debug
        secret (str): Secret key for verification
        algorithms (list): List of allowed algorithms
    
    Returns:
        dict: Decoded token payload or None
    """
    print(f"Token: {token}")
    print(f"Algorithms: {algorithms or ['HS256']}")
    
    payload = decode_and_verify_jwt(token, secret, algorithms)
    
    if payload:
        print("Token is valid!")
        print("Payload:")
        print(json.dumps(payload, indent=2, default=str))
        return payload
    else:
        print("Token is invalid!")
        return None